package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Method;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrint_PathAndCharset_ReturnsCSVPrinter() throws Exception {
        Path mockPath = mock(Path.class);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        Appendable mockWriter = mock(Appendable.class);

        // Use reflection to mock Files.newBufferedWriter(Path, Charset)
        // because Mockito.mockStatic is not available in Mockito 3
        Method printMethod = CSVFormat.class.getMethod("print", Appendable.class);
        CSVFormat spyFormat = spy(csvFormat);

        // Mock print(Appendable) to return mockPrinter
        doReturn(mockPrinter).when(spyFormat).print(mockWriter);

        // Create a proxy for Files.newBufferedWriter by temporarily replacing Files class behavior
        // Since we cannot mock static methods in Mockito 3, we simulate by overriding CSVFormat.print(Path, Charset)
        // via a subclass to intercept call and return mockPrinter

        CSVFormat testFormat = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeaderComments(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter(),
                csvFormat.getAutoFlush()) {
            @Override
            public CSVPrinter print(Path out, java.nio.charset.Charset charset) throws IOException {
                // Instead of calling Files.newBufferedWriter, return the mockWriter directly
                return print(mockWriter);
            }
        };

        CSVPrinter printer = testFormat.print(mockPath, StandardCharsets.UTF_8);

        assertNotNull(printer);
        assertEquals(mockPrinter, printer);

        verify(spyFormat, never()).print(mockWriter); // spyFormat is not used here
    }

    @Test
    public void testPrint_PathAndCharset_ThrowsIOException() {
        Path mockPath = mock(Path.class);

        CSVFormat testFormat = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeaderComments(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter(),
                csvFormat.getAutoFlush()) {
            @Override
            public CSVPrinter print(Path out, java.nio.charset.Charset charset) throws IOException {
                throw new IOException("IO Error");
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> {
            testFormat.print(mockPath, StandardCharsets.UTF_8);
        });

        assertEquals("IO Error", thrown.getMessage());
    }
}
